/**
 * Land -> Cases frontend.
 *
 * Minimal vanilla JS UI for the unified Bhulekh + IGR + eCourts workflow.
 *
 * Dropdowns are populated from a pre-built static catalog
 * (`/data/bhulekh_catalog.json`) generated by
 * `scripts/build_bhulekh_catalog.py`. No live Bhulekh probes happen on
 * page load.
 */
const API_BASE = "/api";
const CATALOG_URL = "/data/bhulekh_catalog.json";
const POLL_INTERVAL_MS = 3000;
/** Stop polling after this many consecutive failed polls (network / 5xx / non-terminal HTTP). */
const MAX_POLL_CONSECUTIVE_FAILURES = 10;

// ── State ────────────────────────────────────────────────────────────────
const state = {
  catalog: null,
  currentWorkflowId: null,
  pollTimer: null,
  pollConsecutiveFailures: 0,
};

// ── DOM refs ──────────────────────────────────────────────────────────────
const form = document.getElementById("land-form");
const districtSel = document.getElementById("district");
const talukaSel = document.getElementById("taluka");
const villageSel = document.getElementById("village");
const surveyPart1 = document.getElementById("survey-part1");
const surveyOption = document.getElementById("survey-option");
const ownerInput = document.getElementById("owner-name");
const submitBtn = document.getElementById("submit-btn");
const errorBanner = document.getElementById("error-banner");
const errorText = document.getElementById("error-text");
const catalogMeta = document.getElementById("catalog-meta");

const progressSection = document.getElementById("progress-section");
const progressFill = document.getElementById("progress-fill");
const progressPctLabel = document.getElementById("progress-pct-label");
const progressStatusLabel = document.getElementById("progress-status-label");
const progressMsg = document.getElementById("progress-msg");
const progressMeta = document.getElementById("progress-meta");

const resultsSection = document.getElementById("results-section");
const resultsTitle = document.getElementById("results-title");
const hitsTable = document.getElementById("hits-table");
const countsStrip = document.getElementById("counts-strip");
const entityBlock = document.getElementById("entity-block");
const artifactsBlock = document.getElementById("artifacts-block");
const resetBtn = document.getElementById("reset-btn");

// ── Init ──────────────────────────────────────────────────────────────────
document.addEventListener("DOMContentLoaded", async () => {
  form.addEventListener("submit", submitWorkflow);
  districtSel.addEventListener("change", onDistrictChange);
  talukaSel.addEventListener("change", onTalukaChange);
  resetBtn.addEventListener("click", resetForm);

  try {
    await loadCatalog();
  } catch (err) {
    showError(`Could not load dropdown catalog: ${err.message}. Run \`python -m scripts.build_bhulekh_catalog\` to build it.`);
  }
});

// ── Catalog loading ───────────────────────────────────────────────────────
async function loadCatalog() {
  const res = await fetch(CATALOG_URL, { cache: "no-cache" });
  if (!res.ok) throw new Error(`HTTP ${res.status}`);
  const cat = await res.json();
  state.catalog = cat;
  populateDistricts(cat.districts || []);
  if (cat.generated_at) {
    catalogMeta.textContent = `Catalog ${cat.districts?.length || 0} district(s), generated ${cat.generated_at}`;
  }
}

function populateDistricts(districts) {
  districtSel.innerHTML = "";
  appendOption(districtSel, "", "Select district");
  districts.forEach((d, idx) => {
    appendOption(districtSel, String(idx), formatLabel(d));
  });
  districtSel.disabled = false;
}

function onDistrictChange() {
  talukaSel.innerHTML = "";
  appendOption(talukaSel, "", "Select taluka");
  villageSel.innerHTML = "";
  appendOption(villageSel, "", "Pick a taluka first");
  villageSel.disabled = true;

  const idx = districtSel.value;
  if (idx === "") {
    talukaSel.disabled = true;
    return;
  }
  const district = state.catalog.districts[Number(idx)];
  (district.talukas || []).forEach((t, tIdx) => {
    appendOption(talukaSel, String(tIdx), formatLabel(t));
  });
  talukaSel.disabled = false;
}

function onTalukaChange() {
  villageSel.innerHTML = "";
  appendOption(villageSel, "", "Select village");

  const dIdx = districtSel.value;
  const tIdx = talukaSel.value;
  if (dIdx === "" || tIdx === "") {
    villageSel.disabled = true;
    return;
  }
  const taluka = state.catalog.districts[Number(dIdx)].talukas[Number(tIdx)];
  const villages = taluka.villages || [];
  villages.forEach(v => {
    appendOption(villageSel, (v.label || "").trim(), formatLabel(v));
  });
  if (!villages.length) {
    villageSel.innerHTML = "";
    appendOption(villageSel, "", "No villages found");
    villageSel.disabled = true;
    return;
  }
  villageSel.disabled = false;
}

function formatLabel(item) {
  const lab = (item.label || "").trim();
  const eng = (item.english || "").trim();
  if (!lab) return eng || "(unnamed)";
  if (!eng || eng.toLowerCase() === lab.toLowerCase()) return lab;
  return `${lab} (${eng})`;
}

function appendOption(select, value, text) {
  const opt = document.createElement("option");
  opt.value = value;
  opt.textContent = text;
  select.appendChild(opt);
}

// ── Submit ────────────────────────────────────────────────────────────────
async function submitWorkflow(e) {
  e.preventDefault();
  hideError();

  const dIdx = districtSel.value;
  const tIdx = talukaSel.value;
  if (dIdx === "" || tIdx === "") {
    showError("Pick a district and taluka.");
    return;
  }
  if (!villageSel.value.trim()) {
    showError("Pick a village.");
    return;
  }
  if (!surveyPart1.value.trim() || !surveyOption.value.trim()) {
    showError("Fill survey base and target survey label.");
    return;
  }

  const district = state.catalog.districts[Number(dIdx)];
  const taluka = district.talukas[Number(tIdx)];
  const villageLabel = villageSel.value.trim();

  const payload = {
    district_label: district.label,
    taluka_label: taluka.label,
    village_label: villageLabel,
    survey_part1: surveyPart1.value.trim(),
    survey_option_label: surveyOption.value.trim(),
    owner_name: ownerInput.value.trim() || null,
  };

  setFormDisabled(true);
  hideResults();
  showProgress("Submitting…", "queued", 0);

  try {
    const res = await fetch(`${API_BASE}/workflows/land-case-search`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload),
    });
    if (!res.ok) {
      const data = await res.json().catch(() => ({}));
      throw new Error(data.detail ? JSON.stringify(data.detail) : `HTTP ${res.status}`);
    }
    const wf = await res.json();
    state.currentWorkflowId = wf.workflow_id;
    showProgress(wf.progress_message || "Starting…", wf.status, wf.progress_pct || 0);
    startPolling(wf.workflow_id);
  } catch (err) {
    showError(`Submission failed: ${err.message}`);
    setFormDisabled(false);
    hideProgress();
  }
}

// ── Polling ───────────────────────────────────────────────────────────────
function startPolling(workflowId) {
  clearPolling();
  state.pollConsecutiveFailures = 0;
  state.pollTimer = setInterval(() => pollStatus(workflowId), POLL_INTERVAL_MS);
  pollStatus(workflowId);
}

function clearPolling() {
  if (state.pollTimer) {
    clearInterval(state.pollTimer);
    state.pollTimer = null;
  }
}

function isTerminalSuccessStatus(wf) {
  const status = String(wf?.status || "").trim().toLowerCase();
  if (status === "completed" || status === "succeeded" || status === "done" || status === "ranked_done") {
    return true;
  }
  // Defensive fallback: some workers may use custom final states but still report
  // 100% and a completed message.
  const pct = Number(wf?.progress_pct || 0);
  const msg = String(wf?.progress_message || "").toLowerCase();
  return pct >= 100 && msg.includes("completed");
}

async function pollStatus(workflowId) {
  try {
    const res = await fetch(`${API_BASE}/workflows/${workflowId}`);
    if (!res.ok) {
      if (res.status === 404) {
        clearPolling();
        showError("Workflow not found.");
        setFormDisabled(false);
        hideProgress();
        return;
      }
      state.pollConsecutiveFailures += 1;
      if (state.pollConsecutiveFailures >= MAX_POLL_CONSECUTIVE_FAILURES) {
        clearPolling();
        showError(
          `Lost connection to the server while checking progress (HTTP ${res.status}). Please try again.`
        );
        setFormDisabled(false);
        hideProgress();
      }
      return;
    }
    const wf = await res.json();
    state.pollConsecutiveFailures = 0;
    showProgress(wf.progress_message || wf.status, wf.status, wf.progress_pct || 0, {
      yearsDone: wf.years_done,
      yearsTotal: wf.years_total,
      totalHits: wf.total_hits,
    });

    if (isTerminalSuccessStatus(wf)) {
      clearPolling();
      await loadFinalResults(workflowId);
    } else if (wf.status === "failed") {
      clearPolling();
      hideProgress();
      showError(wf.error_message || "Workflow failed.");
      setFormDisabled(false);
    }
  } catch (err) {
    console.error("Poll error:", err);
    state.pollConsecutiveFailures += 1;
    if (state.pollConsecutiveFailures >= MAX_POLL_CONSECUTIVE_FAILURES) {
      clearPolling();
      showError(
        "Lost connection while checking progress. Check your network and try again."
      );
      setFormDisabled(false);
      hideProgress();
    }
  }
}

// ── Final results ─────────────────────────────────────────────────────────
async function loadFinalResults(workflowId) {
  try {
    const [resultsRes, artifactsRes] = await Promise.all([
      fetch(`${API_BASE}/workflows/${workflowId}/results`),
      fetch(`${API_BASE}/workflows/${workflowId}/artifacts`),
    ]);
    if (!resultsRes.ok) throw new Error(`results HTTP ${resultsRes.status}`);
    const results = await resultsRes.json();
    const artifacts = artifactsRes.ok ? await artifactsRes.json() : null;

    hideProgress();
    renderResults(workflowId, results, artifacts);
    setFormDisabled(false);
    resultsSection.scrollIntoView({ behavior: "smooth", block: "start" });
  } catch (err) {
    showError(`Loading results failed: ${err.message}`);
    setFormDisabled(false);
    hideProgress();
  }
}

function renderResults(workflowId, results, artifacts) {
  const container = document.getElementById("report-container");
  container.innerHTML = "";
  container.appendChild(buildReportCard(workflowId, results, artifacts));
  resultsSection.style.display = "block";
}

// ── Report card builder ───────────────────────────────────────────────────

function buildReportCard(workflowId, results, artifacts) {
  const card = el("div", "report-card");

  // ── Header ──
  const header = el("div", "rpt-header");
  const hLeft = el("div", "rpt-header-left");
  const surveyLabel = escHtml(results.survey_option_label || "");
  const villageLabel = escHtml(results.village_label || results.entity?.village_label || "");
  const titleDiv = el("div", "rpt-title");
  titleDiv.textContent = surveyLabel
    ? `Survey No. ${surveyLabel}${villageLabel ? `, ${villageLabel}` : ""}`
    : "Survey results";

  const now = new Date();
  const metaDiv = el("div", "rpt-meta");
  const districtParts = [
    results.district_label,
    results.taluka_label,
  ].filter(Boolean);
  const igrYears = results.ownership_timeline?.length
    ? (() => {
        const years = results.ownership_timeline.map(t => parseInt(t.year, 10)).filter(Boolean);
        return years.length ? `IGR records: ${Math.min(...years)}–${now.getFullYear()}` : "";
      })()
    : "";
  metaDiv.textContent = [
    districtParts.join(" · "),
    `Generated ${now.toLocaleDateString("en-IN", { day: "numeric", month: "short", year: "numeric" })}`,
    igrYears,
  ].filter(Boolean).join("  ·  ");

  hLeft.appendChild(titleDiv);
  hLeft.appendChild(metaDiv);

  const hRight = el("div", "rpt-header-right");
  const flagged = !!results.flagged;
  const badge = el("span", `rpt-badge ${flagged ? "rpt-badge-flagged" : "rpt-badge-clear"}`);
  badge.textContent = flagged ? "⚑ Flagged" : "✓ Clear";
  hRight.appendChild(badge);
  if (artifacts?.ranked_csv_path) {
    const csvLink = el("a", "btn btn-outline btn-sm");
    csvLink.href = `${API_BASE}/workflows/${workflowId}/artifact/csv`;
    csvLink.target = "_blank";
    csvLink.rel = "noopener";
    csvLink.textContent = "↓ CSV";
    hRight.appendChild(csvLink);
  }
  if (artifacts?.pdf_path) {
    const pdfLink = el("a", "btn btn-outline btn-sm");
    pdfLink.href = `${API_BASE}/workflows/${workflowId}/artifact/pdf`;
    pdfLink.target = "_blank";
    pdfLink.rel = "noopener";
    pdfLink.textContent = "↓ PDF";
    hRight.appendChild(pdfLink);
  }

  header.appendChild(hLeft);
  header.appendChild(hRight);
  card.appendChild(header);

  // ── Stats ──
  const stats = el("div", "rpt-stats");
  const sigCount = (results.litigation_signals || []).length;
  const statDefs = [
    ["CURRENT OWNER",       results.current_owner || "—",                   false],
    ["TOTAL TRANSACTIONS",  `${results.total_transactions || 0} entries`,   false],
    ["LITIGATION SIGNALS",  `${sigCount} case${sigCount !== 1 ? "s" : ""}`, sigCount > 0],
    ["TITLE PERIOD",        results.title_period_years != null ? `${results.title_period_years} years` : "—", false],
  ];
  statDefs.forEach(([label, value, warn]) => {
    const box = el("div", "rpt-stat");
    const lbl = el("div", "rpt-stat-label");
    lbl.textContent = label;
    const val = el("div", `rpt-stat-value${warn ? " rpt-stat-warn" : ""}`);
    val.textContent = value;
    box.appendChild(lbl);
    box.appendChild(val);
    stats.appendChild(box);
  });
  card.appendChild(stats);

  // ── 7/12 entity summary ──
  const entityLines = buildEntityLines(results);
  if (entityLines.length) {
    const sec = el("div", "rpt-section");
    const title = el("div", "rpt-section-title");
    title.textContent = "LAND RECORD (7/12 EXTRACT)";
    sec.appendChild(title);
    const box = el("div", "rpt-entity");
    box.innerHTML = entityLines.join("<br />");
    sec.appendChild(box);
    card.appendChild(sec);
  }

  // ── Ownership timeline ──
  const timeline = results.ownership_timeline || [];
  if (timeline.length) {
    card.appendChild(buildTimelineSection(timeline));
  }

  // ── Litigation signals ──
  const signals = results.litigation_signals || [];
  if (signals.length) {
    card.appendChild(buildSignalsSection(signals));
  } else {
    const sec = el("div", "rpt-section");
    const title = el("div", "rpt-section-title");
    title.textContent = "LITIGATION SIGNALS";
    sec.appendChild(title);
    const none = el("p");
    none.style.cssText = "font-size:0.85rem;color:var(--text-muted)";
    none.textContent = "No litigation cases found linked to this survey.";
    sec.appendChild(none);
    card.appendChild(sec);
  }

  return card;
}

function buildEntityLines(results) {
  const lines = [];
  if (results.owner_name) {
    lines.push(`<strong>Owner input:</strong> ${escHtml(results.owner_name)}`);
  }
  if (results.entity?.occupant_primary_name) {
    lines.push(`<strong>7/12 occupant:</strong> ${escHtml(results.entity.occupant_primary_name)}`);
  }
  if (results.entity?.occupant_candidates?.length) {
    lines.push(`<strong>Other occupants:</strong> ${results.entity.occupant_candidates.map(escHtml).join(", ")}`);
  }
  if (results.entity?.mutation_numbers?.length) {
    lines.push(`<strong>Mutations:</strong> ${results.entity.mutation_numbers.map(escHtml).join(", ")}`);
  }
  if (results.igr_purchaser_names?.length) {
    lines.push(`<strong>IGR names found:</strong> ${results.igr_purchaser_names.map(escHtml).join(", ")}`);
  }
  return lines;
}

const TL_VISIBLE = 3;

function buildTimelineSection(timeline) {
  const sec = el("div", "rpt-section");
  const title = el("div", "rpt-section-title");
  title.textContent = "OWNERSHIP TIMELINE";
  sec.appendChild(title);

  const wrap = el("div", "timeline");

  const renderItem = (t) => {
    const item = el("div", `tl-item${t.litigation_linked ? " tl-flagged" : ""}`);
    const dot = el("div", "tl-dot");
    const body = el("div", "tl-body");

    const titleRow = el("div", "tl-title");
    const arrow = t.seller && t.buyer
      ? `${escHtml(t.seller)} → ${escHtml(t.buyer)}`
      : escHtml(t.buyer || t.seller || "—");
    titleRow.innerHTML = `${escHtml(t.doc_type || t.doc_type_marathi)} — ${arrow}`;
    if (t.litigation_linked) {
      const tag = el("span", "tl-tag tl-tag-linked");
      tag.textContent = "Litigation linked";
      titleRow.appendChild(tag);
    }

    const meta = el("div", "tl-meta");
    const metaParts = [];
    if (t.doc_no) metaParts.push(`Doc No. ${escHtml(t.doc_no)}`);
    if (t.sro_name) metaParts.push(escHtml(t.sro_name));
    meta.innerHTML = metaParts.join(" · ");

    body.appendChild(titleRow);
    body.appendChild(meta);

    const date = el("div", "tl-date");
    date.textContent = t.reg_date_fmt || t.year || "";

    item.appendChild(dot);
    item.appendChild(body);
    item.appendChild(date);
    return item;
  };

  const visibleItems = timeline.slice(0, TL_VISIBLE);
  const hiddenItems = timeline.slice(TL_VISIBLE);

  visibleItems.forEach(t => wrap.appendChild(renderItem(t)));

  // Hidden items container
  const hiddenWrap = el("div");
  hiddenWrap.style.display = "none";
  hiddenItems.forEach(t => hiddenWrap.appendChild(renderItem(t)));
  wrap.appendChild(hiddenWrap);

  if (hiddenItems.length) {
    const expandBtn = el("button", "tl-expand-btn");
    expandBtn.textContent = `... ${hiddenItems.length} earlier entr${hiddenItems.length === 1 ? "y" : "ies"} ▾`;
    expandBtn.addEventListener("click", () => {
      hiddenWrap.style.display = "block";
      expandBtn.style.display = "none";
    });
    wrap.appendChild(expandBtn);
  }

  sec.appendChild(wrap);
  return sec;
}

function buildSignalsSection(signals) {
  const sec = el("div", "rpt-section");
  const title = el("div", "rpt-section-title");
  title.textContent = "LITIGATION SIGNALS";
  sec.appendChild(title);

  const list = el("div", "signals-list");
  signals.forEach(s => {
    const item = el("div", `signal-item sig-${s.relevance}`);
    const left = el("div", "signal-left");

    const parties = el("div", "signal-parties");
    parties.textContent = s.parties || "—";

    const metaParts = [];
    if (s.case_type) metaParts.push(s.case_type);
    if (s.court) metaParts.push(s.court);
    if (s.year) metaParts.push(s.year);
    if (s.case_status) metaParts.push(s.is_pending ? "Pending" : s.case_status);
    const meta = el("div", "signal-meta");
    meta.textContent = metaParts.join(" · ");

    left.appendChild(parties);
    left.appendChild(meta);

    const rel = el("div", "signal-relevance");
    rel.textContent = `Relevance: ${s.relevance}`;

    item.appendChild(left);
    item.appendChild(rel);
    list.appendChild(item);
  });
  sec.appendChild(list);
  return sec;
}

// ── DOM element helper ────────────────────────────────────────────────────
function el(tag, className) {
  const node = document.createElement(tag);
  if (className) node.className = className;
  return node;
}

function renderArtifacts(workflowId, artifacts) {
  artifactsBlock.innerHTML = "";
  if (!artifacts) return;
  const items = [];
  if (artifacts.pdf_path) items.push(["pdf", "Mahabhulekh PDF"]);
  if (artifacts.ranked_csv_path) items.push(["csv", "Ranked CSV"]);
  if (artifacts.html_path) items.push(["html", "Submitted HTML"]);
  if (!items.length) return;

  const heading = document.createElement("h3");
  heading.className = "artifacts-heading";
  heading.textContent = "Artifacts";
  artifactsBlock.appendChild(heading);

  const list = document.createElement("div");
  list.className = "artifacts-list";
  items.forEach(([kind, label]) => {
    const a = document.createElement("a");
    a.href = `${API_BASE}/workflows/${workflowId}/artifact/${kind}`;
    a.target = "_blank";
    a.rel = "noopener";
    a.className = "btn btn-outline btn-sm";
    a.textContent = label;
    list.appendChild(a);
  });
  artifactsBlock.appendChild(list);
}

function appendChip(container, label, value) {
  const span = document.createElement("span");
  span.className = "count-chip";
  span.innerHTML = `<strong>${escHtml(String(value))}</strong> ${escHtml(label)}`;
  container.appendChild(span);
}

// ── UI helpers ────────────────────────────────────────────────────────────
function showProgress(message, status, pct, meta) {
  progressSection.style.display = "block";
  progressFill.style.width = `${pct || 0}%`;
  progressPctLabel.textContent = `${pct || 0}%`;
  progressStatusLabel.textContent = friendlyStatus(status, pct);
  const detail = (message && String(message).trim()) || "Please wait while we process your request.";
  progressMsg.textContent = detail;
  if (meta && meta.yearsTotal > 0) {
    progressMeta.textContent = `Step ${meta.yearsDone != null ? meta.yearsDone : 0} of ${meta.yearsTotal}`;
  } else {
    progressMeta.textContent = "";
  }
}

function hideProgress() {
  progressSection.style.display = "none";
}

function hideResults() {
  resultsSection.style.display = "none";
}

function setFormDisabled(disabled) {
  submitBtn.disabled = disabled;
  submitBtn.textContent = disabled ? "Running…" : "Run land → cases";
  [districtSel, talukaSel, villageSel, surveyPart1, surveyOption, ownerInput].forEach(el => {
    el.disabled = disabled;
  });
  if (!disabled) {
    if (districtSel.value === "") talukaSel.disabled = true;
    if (talukaSel.value === "" || districtSel.value === "") villageSel.disabled = true;
  }
}

function showError(msg) {
  errorText.textContent = msg;
  errorBanner.style.display = "flex";
}

function hideError() {
  errorBanner.style.display = "none";
}

function resetForm() {
  hideResults();
  hideProgress();
  hideError();
  clearPolling();
  state.pollConsecutiveFailures = 0;
  state.currentWorkflowId = null;
  setFormDisabled(false);
  form.reset();
  districtSel.dispatchEvent(new Event("change"));
  window.scrollTo({ top: 0, behavior: "smooth" });
}

function escHtml(str) {
  return String(str)
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;");
}

function friendlyStatus(status, pct) {
  const s = String(status || "").toLowerCase();
  const p = Number(pct || 0);
  if (s === "failed") return "Unable to complete";
  if (isTerminalSuccessStatus({ status: s, progress_pct: p })) return "Completed";
  if (s === "igr_running") return "Searching land records";
  if (p >= 90 || s.includes("rank") || s.includes("done")) return "Finalizing";
  if (p >= 45 || s.includes("ecourt") || s.includes("search")) return "Gathering case records";
  return "Preparing your results";
}

function normalizePublicCases(results) {
  const apiCases = Array.isArray(results?.ecourts_api_cases) ? results.ecourts_api_cases : [];
  const normalizedApiCases = apiCases
    .map((c) => ({
      cnr_number: c.cnr_number || "",
      case_type: c.case_type || "",
      case_type_raw: c.case_type_raw || "",
      case_status: c.case_status || (c.is_pending ? "Pending" : "Closed"),
      court: c.court || "",
      court_no: c.court_no || "",
      district: c.district || "",
      state: c.state || "",
      case_number: c.case_number || "",
      cnr_year: c.cnr_year || "",
      filing_number: c.filing_number || "",
      filing_date: c.filing_date || "",
      registration_number: c.registration_number || "",
      registration_date: c.registration_date || "",
      first_hearing_date: c.first_hearing_date || "",
      next_hearing_date: c.next_hearing_date || "",
      decision_date: c.decision_date || "",
      petitioners_text: (Array.isArray(c.petitioners) ? c.petitioners : []).join(", "),
      respondents_text: (Array.isArray(c.respondents) ? c.respondents : []).join(", "),
      petitioner_advocates_text: (Array.isArray(c.petitioner_advocates) ? c.petitioner_advocates : []).join(", "),
      respondent_advocates_text: (Array.isArray(c.respondent_advocates) ? c.respondent_advocates : []).join(", "),
      case_category_facet_path: c.case_category_facet_path || "",
      final_rank: c.final_rank ?? "",
    }))
    .filter((c) => c.cnr_number || c.case_number || c.court || c.case_type || c.case_type_raw);
  if (normalizedApiCases.length) {
    return normalizedApiCases;
  }

  // Fallback for older runs where normalized API cases were not persisted.
  const hits = Array.isArray(results?.hits) ? results.hits : [];
  return hits.map((h) => ({
    cnr_number: h.cnr_number || "",
    case_type: h.case_type || "",
    case_type_raw: "",
    case_status: "",
    court: h.court || "",
    court_no: "",
    district: "",
    state: "",
    case_number: h.case_id || "",
    cnr_year: h.search_year || "",
    filing_number: "",
    filing_date: "",
    registration_number: "",
    registration_date: "",
    first_hearing_date: "",
    next_hearing_date: "",
    decision_date: "",
    petitioners_text: "",
    respondents_text: "",
    petitioner_advocates_text: "",
    respondent_advocates_text: "",
    case_category_facet_path: "",
    final_rank: h.final_rank ?? "",
  }));
}

